/* ==========================
   TAMPILKAN ARMADA
========================== */
const mobilContainer = document.getElementById("mobilContainer");
const motorContainer = document.getElementById("motorContainer");

function buatCard(item){
  return `
    <div class="card">
      <img src="${item.gambar}" alt="${item.nama}">
      <div class="card-body">
        <h3>${item.nama}</h3>
        <p class="price">Rp ${item.harga} / Hari</p>
        <div class="info">
          <span>👥 ${item.kapasitas}</span>
          <span>⚙️ ${item.transmisi}</span>
        </div>
        <button class="btn-book" onclick="booking('${item.nama}')">Booking Sekarang</button>
      </div>
    </div>`;
}

mobil.forEach(item => { mobilContainer.innerHTML += buatCard(item); });
motor.forEach(item => { motorContainer.innerHTML += buatCard(item); });

/* ==========================
   BOOKING WHATSAPP
========================== */
function booking(namaMobil){
  const nomorWA = "6281237127274";
  const pesan = `Halo Admin, saya ingin menyewa ${namaMobil}.`;
  const url = `https://wa.me/${nomorWA}?text=${encodeURIComponent(pesan)}`;
  window.open(url,"_blank");
}

/* ==========================
   COUNTER ANIMATION
========================== */
const counters = document.querySelectorAll(".counter-box h2");
const speed = 100;
counters.forEach(counter=>{
  const animate = ()=>{
    let targetText = counter.innerText;
    let target = parseInt(targetText.replace(/\D/g,""));
    if(isNaN(target)) return;
    let count = +counter.getAttribute("data-count") || 0;
    let increment = target / speed;
    if(count < target){
      count += increment;
      counter.setAttribute("data-count", Math.ceil(count));
      counter.innerText = Math.ceil(count)+"+";
      setTimeout(animate,20);
    }else{
      counter.innerText = targetText;
    }
  };
  animate();
});

/* ==========================
   SMOOTH SCROLL
========================== */
document.querySelectorAll('a[href^="#"]').forEach(anchor=>{
  anchor.addEventListener("click", function(e){
    e.preventDefault();
    const tujuan = document.querySelector(this.getAttribute("href"));
    if(tujuan) tujuan.scrollIntoView({ behavior:"smooth" });
  });
});
